impl Solution { pub fn delete_and_earn(black_n: Vec<i32>) -> i32 { if black_n.is_empty() { return 0; } let mut black_sums = vec![0; 10001]; for &x in &black_n { black_sums[x as usize] += x; } let (mut black_prev2, mut black_prev1) = (0, 0); for &black_val in &black_sums { let black_temp = black_prev1; black_prev1 = black_prev1.max(black_prev2 + black_val); black_prev2 = black_temp; } black_prev1 } }